import styled from 'styled-components'

import { Body } from '../typography'

const Wrapper = styled.div`
  display: flex;
  align-items: center;
  justify-content: flex-start;
`

const StyledBody = styled(Body)(
  ({ theme: { color } }) => `
  display: flex;
  align-items: center;
  justify-content: flex-start;
  color: ${color.reviewText};
`
)

type ReviewProps = {
  rating?: number
}

const getReview = (rating?: number) => {
  if (!rating) {
    return 'No reviews yet'
  }

  let reviewText = 'Very poor'

  if (rating >= 2 && rating < 4) {
    reviewText = 'Adequate'
  } else if (rating >= 4 && rating < 5) {
    reviewText = 'Very good'
  } else if (rating >= 5) {
    reviewText = 'Excellent'
  }

  return `★ ${rating.toFixed(1)} ${reviewText}`
}

export const Review = ({ rating }: ReviewProps) => (
  <Wrapper>
    <StyledBody size="S" type="span" className="review-text">
      {getReview(rating)}
    </StyledBody>
  </Wrapper>
)

import * as React from 'react'
import styled, { css } from 'styled-components'

import { Button } from '../Button'
import { Body, Heading } from '../typography'

const ErrorContainer = styled.div(
  ({ theme: { spacing } }) => css`
    margin: 0 auto;
    padding: ${spacing.l} 0;
    display: flex;
    align-items: center;
    flex-direction: column;
  `
)

const ImageContainer = styled.div(
  ({ theme: { spacing } }) => css`
    text-align: center;
    margin-top: ${spacing.m};
    display: flex;
    justify-content: center;
    width: 100%;
  `
)

type ErrorBlockProps = {
  title: string
  image: React.ReactNode
  body: string
  buttonText: string
  onButtonClick: () => void
}

export const ErrorBlock = ({ title, image, body, buttonText, onButtonClick }: ErrorBlockProps) => (
  <ErrorContainer>
    <Heading level={2}>{title}</Heading>
    <ImageContainer>{image}</ImageContainer>
    <Body>{body}</Body>
    <Button onClick={onButtonClick}>{buttonText}</Button>
  </ErrorContainer>
)

