import { useState } from 'react'
import type { Meta, StoryObj } from '@storybook/react-vite'
import { expect, userEvent, within } from 'storybook/test'

import { Modal } from './Modal'
import { Button } from '../Button'

const meta = {
  component: Modal,
  tags: ['ai-generated', 'needs-work'],
} satisfies Meta<typeof Modal>

export default meta
type Story = StoryObj<typeof meta>

export const Open: Story = {
  args: {
    isOpen: true,
    onClose: () => {},
    children: <p>Modal content goes here</p>,
  },
  play: async ({ canvasElement }) => {
    const doc = canvasElement.ownerDocument
    const modal = await within(doc.body).findByTestId('modal')
    await expect(modal).toBeVisible()
  },
}

export const Closed: Story = {
  args: {
    isOpen: false,
    onClose: () => {},
    children: <p>Hidden content</p>,
  },
}

export const WithInteraction: Story = {
  render: () => {
    const [isOpen, setIsOpen] = useState(false)
    return (
      <>
        <Button onClick={() => setIsOpen(true)}>Open Modal</Button>
        <Modal isOpen={isOpen} onClose={() => setIsOpen(false)}>
          <p>Modal content</p>
        </Modal>
      </>
    )
  },
  play: async ({ canvas, canvasElement }) => {
    await userEvent.click(canvas.getByRole('button', { name: /open modal/i }))
    const doc = canvasElement.ownerDocument
    const modal = await within(doc.body).findByTestId('modal')
    await expect(modal).toBeVisible()
    await userEvent.click(within(doc.body).getByRole('button', { name: /close modal/i }))
    await expect(within(doc.body).queryByTestId('modal')).not.toBeInTheDocument()
  },
}

